import { useState, useEffect } from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuth }    from './context/AuthContext';
import SplashScreen   from './components/SplashScreen';
import Navbar from './components/Navbar';
import Landing        from './pages/Landing';
import Dashboard from './pages/Dashboard';
import Login from './pages/Login';
import Register from './pages/Register';
import CreatePost from './pages/CreatePost';
import AdminPanel from './pages/Admin';
import AuthCallback from './pages/AuthCallback';

const ProtectedRoute = ({ children }) => {
  const { user } = useAuth();
  return user ? children : <Navigate to="/login" replace />;
};

const AdminRoute = ({ children }) => {
  const { user } = useAuth();
  if (!user)                 return <Navigate to="/login"    replace />;
  if (user.role !== 'admin') return <Navigate to="/dashboard" replace />;
  return children;
};


export default function App() {
  const { user }              = useAuth();
  const [splash, setSplash]   = useState(true);

  if (splash) return <SplashScreen onDone={() => setSplash(false)} />;

  return (
    <div className="min-h-screen bg-slate-50">
      {user && <Navbar />}
      <Routes>
        <Route path="/"         element={!user ? <Landing />  : <Navigate to="/dashboard" />} />
        <Route path="/login"    element={!user ? <Login />    : <Navigate to="/dashboard" />} />
        <Route path="/register" element={!user ? <Register /> : <Navigate to="/dashboard" />} />
        <Route path="/dashboard" element={<ProtectedRoute><Dashboard  /></ProtectedRoute>} />
        <Route path="/create"    element={<ProtectedRoute><CreatePost /></ProtectedRoute>} />
        <Route path="/admin"     element={<AdminRoute>    <AdminPanel /></AdminRoute>}     />
        <Route path="*"          element={<Navigate to={user ? '/dashboard' : '/'} />}    />
                  <Route path="/auth/callback" element={<AuthCallback />} />
      </Routes>
    </div>
  );
}

import { useEffect } from 'react';
import { MapContainer, TileLayer, Marker, Popup, Circle, useMap } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import TrustBadge from './TrustBadge';

// Fix Leaflet default icon issue with Vite
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl:       'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl:     'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

// Custom colored marker icons per category
const categoryIcon = (category) => {
  const colors = {
    Jobs:    '#1B3A6B',
    Rentals: '#7C3AED',
    Events:  '#16A34A',
    Alerts:  '#F97316',
  };
  const color = colors[category] || '#1B3A6B';
  return L.divIcon({
    className: '',
    html: `<div style="
      background:${color};
      width:32px;height:32px;border-radius:50% 50% 50% 0;
      transform:rotate(-45deg);border:3px solid white;
      box-shadow:0 2px 8px rgba(0,0,0,0.3);
    "></div>`,
    iconSize:   [32, 32],
    iconAnchor: [16, 32],
    popupAnchor:[0, -32],
  });
};

// Re-center map when location changes
function RecenterMap({ lat, lng }) {
  const map = useMap();
  useEffect(() => {
    if (lat && lng) map.setView([lat, lng], 14);
  }, [lat, lng]);
  return null;
}

export default function MapView({ posts, location, radius }) {
  if (!location) return (
    <div className="h-64 bg-slate-100 rounded-2xl flex items-center justify-center">
      <p className="text-gray-400 text-sm">Detecting your location...</p>
    </div>
  );

  return (
    <div className="rounded-2xl overflow-hidden border border-gray-200 shadow-sm" style={{ height: '420px' }}>
      <MapContainer
        center={[location.lat, location.lng]}
        zoom={14}
        style={{ height: '100%', width: '100%' }}
        zoomControl={true}
      >
        <TileLayer
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          attribution='&copy; OpenStreetMap contributors'
        />

        <RecenterMap lat={location.lat} lng={location.lng} />

        {/* User location radius circle */}
        <Circle
          center={[location.lat, location.lng]}
          radius={radius}
          pathOptions={{
            color:       '#1B3A6B',
            fillColor:   '#1B3A6B',
            fillOpacity: 0.08,
            weight:      2,
            dashArray:   '6 4',
          }}
        />

        {/* User location marker */}
        <Marker
          position={[location.lat, location.lng]}
          icon={L.divIcon({
            className: '',
            html: `<div style="
              width:16px;height:16px;background:#F97316;
              border-radius:50%;border:3px solid white;
              box-shadow:0 0 0 3px rgba(249,115,22,0.3);
            "></div>`,
            iconSize:   [16, 16],
            iconAnchor: [8, 8],
          })}
        >
          <Popup><strong>You are here</strong></Popup>
        </Marker>

        {/* Post markers */}
        {posts.map((post) => {
          const [lng, lat] = post.location.coordinates;
          return (
            <Marker
              key={post._id}
              position={[lat, lng]}
              icon={categoryIcon(post.category)}
            >
              <Popup maxWidth={220}>
                <div style={{ fontFamily: 'sans-serif', minWidth: '180px' }}>
                  <div style={{ display:'flex', alignItems:'center', gap:'6px', marginBottom:'6px' }}>
                    <span style={{
                      fontSize:'10px', padding:'2px 8px', borderRadius:'20px',
                      background:'#EFF6FF', color:'#1B3A6B', fontWeight:'600'
                    }}>{post.category}</span>
                  </div>
                  <p style={{ fontWeight:'600', fontSize:'13px', marginBottom:'4px' }}>
                    {post.title}
                  </p>
                  <p style={{ fontSize:'11px', color:'#6B7280', marginBottom:'8px', lineHeight:'1.4' }}>
                    {post.description.slice(0, 80)}...
                  </p>
                  {post.contact && (
                    <p style={{ fontSize:'11px', color:'#1B3A6B', marginBottom:'6px' }}>
                      📞 {post.contact}
                    </p>
                  )}
                  <div style={{ display:'flex', gap:'6px' }}>
                    {post.contact && (
                      <a href={`tel:${post.contact}`} style={{
                        flex:1, background:'#1B3A6B', color:'white',
                        padding:'5px', borderRadius:'8px', fontSize:'11px',
                        textAlign:'center', textDecoration:'none', fontWeight:'500'
                      }}>Call</a>
                    )}
                    {post.contact && (
                      <a href={`https://wa.me/91${post.contact}`} target="_blank" rel="noreferrer"
                         style={{
                           flex:1, background:'#25D366', color:'white',
                           padding:'5px', borderRadius:'8px', fontSize:'11px',
                           textAlign:'center', textDecoration:'none', fontWeight:'500'
                         }}>WhatsApp</a>
                    )}
                  </div>
                </div>
              </Popup>
            </Marker>
          );
        })}
      </MapContainer>
    </div>
  );
}

import { useEffect, useState } from 'react';
import { MapPin } from 'lucide-react';

export default function SplashScreen({ onDone }) {
  const [phase, setPhase] = useState(0);

  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 400);
    const t2 = setTimeout(() => setPhase(2), 900);
    const t3 = setTimeout(() => setPhase(3), 1500);
    const t4 = setTimeout(() => onDone(), 2200);
    return () => [t1, t2, t3, t4].forEach(clearTimeout);
  }, []);

  return (
    <div className="fixed inset-0 z-50 flex flex-col items-center justify-center"
         style={{ background: 'linear-gradient(135deg, #1B3A6B 0%, #0F2447 100%)' }}>

      {/* Logo */}
      <div className={`flex flex-col items-center transition-all duration-500 ${
        phase >= 1 ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-6'
      }`}>
        <div className="relative mb-4">
          <div className="w-20 h-20 bg-orange-500 rounded-3xl flex items-center 
                          justify-center shadow-2xl">
            <MapPin size={40} color="white" strokeWidth={2.5} />
          </div>
          {/* Pulse ring */}
          <div className={`absolute inset-0 rounded-3xl border-2 border-orange-400
                          transition-all duration-700 ${
            phase >= 2 ? 'scale-150 opacity-0' : 'scale-100 opacity-100'
          }`} />
        </div>

        <h1 className="text-white text-3xl font-bold tracking-tight">
          NearNotify
        </h1>
        <p className="text-blue-200 text-sm mt-1">
          Hyperlocal Smart Notice Board
        </p>
      </div>

      {/* Loading dots */}
      <div className={`flex gap-2 mt-12 transition-all duration-500 ${
        phase >= 2 ? 'opacity-100' : 'opacity-0'
      }`}>
        {[0, 1, 2].map((i) => (
          <div
            key={i}
            className="w-2 h-2 bg-orange-400 rounded-full"
            style={{
              animation: phase >= 2 ? `bounce 0.8s ease-in-out ${i * 0.15}s infinite` : 'none'
            }}
          />
        ))}
      </div>

      {/* Tagline */}
      <p className={`text-blue-300 text-xs mt-6 transition-all duration-500 ${
        phase >= 3 ? 'opacity-100' : 'opacity-0'
      }`}>
        Discovering what's near you...
      </p>

      <style>{`
        @keyframes bounce {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-8px); }
        }
      `}</style>
    </div>
  );
}

