import { useState, useEffect } from 'react';
import api   from '../services/api';
import toast from 'react-hot-toast';
import TrustBadge from '../components/TrustBadge';
import { CheckCircle, XCircle, UserX, BarChart3,
         Users, FileText, Clock, AlertTriangle, Shield } from 'lucide-react';

const TABS = ['Pending', 'Approved', 'Rejected', 'Reported'];

const CAT_STYLE = {
  Jobs:    'bg-blue-50   text-blue-700   border-blue-200',
  Rentals: 'bg-purple-50 text-purple-700 border-purple-200',
  Events:  'bg-green-50  text-green-700  border-green-200',
  Alerts:  'bg-orange-50 text-orange-700 border-orange-200',
};

export default function AdminPanel() {
  const [posts,   setPosts  ] = useState([]);
  const [stats,   setStats  ] = useState(null);
  const [tab,     setTab    ] = useState('Pending');
  const [loading, setLoading] = useState(false);

  const fetchStats = async () => {
    try {
      const { data } = await api.get('/admin/stats');
      setStats(data.stats);
    } catch {}
  };

  const fetchPosts = async () => {
    setLoading(true);
    try {
      const { data } = await api.get(`/admin/posts?status=${tab.toLowerCase()}`);
      setPosts(data.posts || []);
    } catch {
      toast.error('Failed to load posts.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchStats(); }, []);
  useEffect(() => { fetchPosts(); }, [tab]);

  const approve = async (id) => {
    try {
      await api.put(`/admin/posts/${id}/approve`);
      toast.success('Post approved! ✓');
      setPosts((p) => p.filter((x) => x._id !== id));
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed.');
    }
  };

  const reject = async (id) => {
    const reason = prompt('Rejection reason:') || 'Did not meet guidelines.';
    try {
      await api.put(`/admin/posts/${id}/reject`, { reason });
      toast.success('Post rejected.');
      setPosts((p) => p.filter((x) => x._id !== id));
      fetchStats();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed.');
    }
  };

  const blockUser = async (userId) => {
    if (!confirm('Block this user?')) return;
    try {
      await api.put(`/admin/users/${userId}/toggle-active`);
      toast.success('User blocked.');
      fetchPosts();
    } catch {
      toast.error('Failed to block user.');
    }
  };

  return (
    <div className="max-w-5xl mx-auto px-4 py-6">

      {/* Header */}
      <div className="flex items-center gap-3 mb-6">
        <div className="w-10 h-10 bg-purple-100 rounded-xl flex items-center justify-center">
          <Shield size={20} className="text-purple-700" />
        </div>
        <div>
          <h1 className="text-xl font-bold text-gray-900">Admin Dashboard</h1>
          <p className="text-gray-400 text-xs">Manage posts and users</p>
        </div>
      </div>

      {/* Stats */}
      {stats && (
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-6">
          {[
            { label: 'Pending',  value: stats.pendingPosts,  icon: <Clock size={16} />,       color: 'text-amber-600',  bg: 'bg-amber-50'  },
            { label: 'Approved', value: stats.approvedPosts, icon: <CheckCircle size={16} />, color: 'text-green-600',  bg: 'bg-green-50'  },
            { label: 'Rejected', value: stats.rejectedPosts, icon: <XCircle size={16} />,     color: 'text-red-600',    bg: 'bg-red-50'    },
            { label: 'Users',    value: stats.totalUsers,    icon: <Users size={16} />,        color: 'text-purple-600', bg: 'bg-purple-50' },
          ].map((s) => (
            <div key={s.label} className="card flex items-center gap-3">
              <div className={`w-10 h-10 ${s.bg} ${s.color} rounded-xl flex items-center justify-center flex-shrink-0`}>
                {s.icon}
              </div>
              <div>
                <div className="text-xl font-bold text-gray-900">{s.value}</div>
                <div className="text-xs text-gray-400">{s.label}</div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Tabs */}
      <div className="flex gap-1 bg-slate-100 p-1 rounded-xl mb-5 w-fit">
        {TABS.map((t) => (
          <button key={t} onClick={() => setTab(t)}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              tab === t
                ? 'bg-white text-gray-900 shadow-sm'
                : 'text-gray-500 hover:text-gray-700'
            }`}>
            {t}
            {t === 'Pending' && stats?.pendingPosts > 0 && (
              <span className="ml-1.5 bg-amber-500 text-white text-xs px-1.5 py-0.5 rounded-full">
                {stats.pendingPosts}
              </span>
            )}
          </button>
        ))}
      </div>

      {/* Posts */}
      {loading ? (
        <div className="space-y-3">
          {[...Array(3)].map((_, i) => (
            <div key={i} className="card animate-pulse">
              <div className="h-4 bg-gray-200 rounded w-1/3 mb-2" />
              <div className="h-5 bg-gray-200 rounded w-2/3 mb-2" />
              <div className="h-4 bg-gray-200 rounded w-full" />
            </div>
          ))}
        </div>
      ) : posts.length === 0 ? (
        <div className="text-center py-16">
          <div className="w-14 h-14 bg-slate-100 rounded-full flex items-center 
                          justify-center mx-auto mb-3">
            <FileText size={24} className="text-slate-400" />
          </div>
          <p className="text-gray-500 font-medium">No {tab.toLowerCase()} posts</p>
        </div>
      ) : (
        <div className="space-y-3">
          {posts.map((post) => (
            <div key={post._id} className="card hover:shadow-md transition-all">
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1 min-w-0">

                  {/* Category + status */}
                  <div className="flex items-center gap-2 mb-2 flex-wrap">
                    <span className={`text-xs px-2.5 py-1 rounded-full font-semibold 
                                     border ${CAT_STYLE[post.category]}`}>
                      {post.category}
                    </span>
                    {post.status === 'approved' && (
                      <span className="text-xs px-2.5 py-1 rounded-full font-semibold 
                                       bg-green-50 text-green-700 border border-green-200">
                        Approved
                      </span>
                    )}
                    {post.reports?.length > 0 && (
                      <span className="flex items-center gap-1 text-xs text-red-500 
                                       bg-red-50 px-2 py-1 rounded-full border border-red-200">
                        <AlertTriangle size={11} /> {post.reports.length} report(s)
                      </span>
                    )}
                  </div>

                  <h3 className="font-bold text-gray-900 mb-1">{post.title}</h3>
                  <p className="text-gray-500 text-sm leading-relaxed mb-3 line-clamp-2">
                    {post.description}
                  </p>

                  {/* Meta */}
                  <div className="flex flex-wrap items-center gap-x-3 gap-y-1 text-xs text-gray-400">
                    <span>By <span className="text-gray-700 font-medium">{post.author?.name}</span></span>
                    <TrustBadge badge={post.author?.trustBadge} />
                    {post.contact && <span>📞 {post.contact}</span>}
                    <span>Radius: {post.radius >= 1000 ? `${post.radius/1000}km` : `${post.radius}m`}</span>
                    <span>Expires: {new Date(post.expiresAt).toLocaleDateString()}</span>
                    {post.rejectionReason && (
                      <span className="text-red-500">Reason: {post.rejectionReason}</span>
                    )}
                  </div>
                </div>

                {/* Actions */}
                {tab === 'Pending' && (
                  <div className="flex flex-col gap-2 flex-shrink-0">
                    <button onClick={() => approve(post._id)}
                      className="flex items-center gap-1.5 bg-green-600 text-white 
                                 px-4 py-2 rounded-xl text-sm font-medium 
                                 hover:bg-green-700 transition-all active:scale-95">
                      <CheckCircle size={14} /> Approve
                    </button>
                    <button onClick={() => reject(post._id)}
                      className="flex items-center gap-1.5 bg-red-50 text-red-600 
                                 border border-red-200 px-4 py-2 rounded-xl text-sm 
                                 font-medium hover:bg-red-100 transition-all active:scale-95">
                      <XCircle size={14} /> Reject
                    </button>
                    <button onClick={() => blockUser(post.author?._id)}
                      className="flex items-center gap-1.5 bg-slate-100 text-gray-600 
                                 px-4 py-2 rounded-xl text-sm font-medium 
                                 hover:bg-slate-200 transition-all active:scale-95">
                      <UserX size={14} /> Block
                    </button>
                  </div>
                )}
                {tab === 'Approved' && (
                  <button onClick={() => reject(post._id)}
                    className="flex items-center gap-1.5 bg-red-50 text-red-600 
                               border border-red-200 px-4 py-2 rounded-xl text-sm 
                               font-medium hover:bg-red-100 transition-all">
                    <XCircle size={14} /> Reject
                  </button>
                )}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { useEffect, useContext } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';

// This page handles the redirect from Google OAuth
// URL: /auth/callback?user=<encoded JSON>
const AuthCallback = () => {
  const [params] = useSearchParams();
  const { login } = useContext(AuthContext);
  const navigate = useNavigate();

  useEffect(() => {
    const userParam = params.get('user');
    const error = params.get('error');

    if (error || !userParam) {
      navigate('/login?error=google_failed');
      return;
    }

    try {
      const userData = JSON.parse(decodeURIComponent(userParam));
      login(userData);
      navigate('/');
    } catch {
      navigate('/login?error=google_failed');
    }
  }, []);

  return (
    <div className="flex items-center justify-center min-h-screen">
      <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600"></div>
    </div>
  );
};

export default AuthCallback;

