import { useState, useEffect, useCallback } from 'react';
import api             from '../services/api';
import PostCard        from '../components/PostCard';
import AISummaryBanner from '../components/AISummaryBanner';
import MapView         from '../components/MapView';
import useGeolocation  from '../hooks/useGeolocation';
import { useAuth }     from '../context/AuthContext';
import { Search, SlidersHorizontal, RefreshCw, Map, List, MapPin } from 'lucide-react';
import toast from 'react-hot-toast';

const CATEGORIES = ['All', 'Jobs', 'Rentals', 'Events', 'Alerts'];
const RADII      = [{ label: '500m', value: 500 }, { label: '1km', value: 1000 }, { label: '2km', value: 2000 }, { label: '5km', value: 5000 }];

export default function Dashboard() {
  const { user }                    = useAuth();
  const { location, error: geoErr } = useGeolocation();
  const [posts,    setPosts   ]     = useState([]);
  const [loading,  setLoading ]     = useState(false);
  const [category, setCategory]     = useState('All');
  const [radius,   setRadius  ]     = useState(2000);
  const [search,   setSearch  ]     = useState('');
  const [view,     setView    ]     = useState('list');
  const [showFilter, setShowFilter] = useState(false);

  const fetchPosts = useCallback(async () => {
    if (!location) return;
    setLoading(true);
    try {
      const params = { lat: location.lat, lng: location.lng, radius };
      if (category !== 'All') params.category = category;
      const { data } = await api.get('/posts', { params });
      setPosts(data.posts || []);
    } catch {
      toast.error('Failed to load posts.');
    } finally {
      setLoading(false);
    }
  }, [location, category, radius]);

  useEffect(() => { fetchPosts(); }, [fetchPosts]);

  const filtered = posts.filter((p) =>
    p.title.toLowerCase().includes(search.toLowerCase()) ||
    p.description.toLowerCase().includes(search.toLowerCase())
  );

  // Count by category
  const counts = CATEGORIES.reduce((acc, cat) => {
    acc[cat] = cat === 'All' ? posts.length : posts.filter(p => p.category === cat).length;
    return acc;
  }, {});

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">

      {/* Header */}
      <div className="flex items-start justify-between mb-5">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">
            Discover Nearby
          </h1>
          <p className="text-gray-500 text-sm flex items-center gap-1 mt-1">
            <MapPin size={13} className="text-blue-600" />
            {loading ? 'Loading...' : `${filtered.length} listings within ${radius >= 1000 ? `${radius/1000}km` : `${radius}m`}`}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => setShowFilter(!showFilter)}
            className={`p-2.5 rounded-xl border transition-all ${showFilter ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-gray-200 text-gray-500'}`}>
            <SlidersHorizontal size={18} />
          </button>
          <button onClick={() => setView(view === 'list' ? 'map' : 'list')}
            className={`p-2.5 rounded-xl border transition-all ${view === 'map' ? 'bg-blue-50 border-blue-200 text-blue-600' : 'bg-white border-gray-200 text-gray-500'}`}>
            {view === 'list' ? <Map size={18} /> : <List size={18} />}
          </button>
          <button onClick={fetchPosts}
            className="p-2.5 rounded-xl border bg-white border-gray-200 text-gray-500 hover:text-blue-600 transition-all">
            <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
          </button>
        </div>
      </div>

      {/* AI Summary */}
      <AISummaryBanner />

      {/* Category pills */}
      <div className="flex gap-2 overflow-x-auto pb-1 mb-4 scrollbar-hide">
        {CATEGORIES.map((cat) => (
          <button key={cat} onClick={() => setCategory(cat)}
            className={`pill whitespace-nowrap flex items-center gap-1.5 ${category === cat ? 'pill-active' : 'pill-inactive'}`}>
            {cat}
            <span className={`text-xs px-1.5 py-0.5 rounded-full font-medium ${
              category === cat ? 'bg-white/20 text-white' : 'bg-gray-100 text-gray-500'
            }`}>{counts[cat]}</span>
          </button>
        ))}
      </div>

      {/* Filter panel */}
      {showFilter && (
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-4 mb-4 flex flex-wrap gap-4 items-center">
          <div className="relative flex-1 min-w-48">
            <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input type="text" placeholder="Search posts..."
              value={search} onChange={(e) => setSearch(e.target.value)}
              className="input-field pl-9 py-2.5" />
          </div>
          <div className="flex items-center gap-2">
            <span className="text-sm text-gray-500">Radius:</span>
            <div className="flex gap-1">
              {RADII.map((r) => (
                <button key={r.value} onClick={() => setRadius(r.value)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-medium transition-all ${
                    radius === r.value ? 'bg-blue-700 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                  }`}>{r.label}</button>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Map or List view */}
      {view === 'map' ? (
        <MapView posts={filtered} location={location} radius={radius} />
      ) : loading ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {[...Array(6)].map((_, i) => (
            <div key={i} className="card animate-pulse">
              <div className="h-3 bg-gray-200 rounded-full w-1/4 mb-3" />
              <div className="h-5 bg-gray-200 rounded-lg w-3/4 mb-2" />
              <div className="h-4 bg-gray-200 rounded-lg w-full mb-1" />
              <div className="h-4 bg-gray-200 rounded-lg w-2/3 mb-4" />
              <div className="h-10 bg-gray-200 rounded-xl" />
            </div>
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-20">
          <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <MapPin size={28} className="text-slate-400" />
          </div>
          <h3 className="text-gray-700 font-semibold text-lg mb-1">No posts found near you</h3>
          <p className="text-gray-400 text-sm">Try increasing the radius or changing the category</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {filtered.map((post) => (
            <PostCard key={post._id} post={post}
              onReport={(id) => setPosts((prev) => prev.filter((p) => p._id !== id))} />
          ))}
        </div>
      )}
    </div>
  );
}
